const items = $input.all();
return items.map(item => {
  const d = item.json;
  const mode = d['hub.mode'];
  const challenge = d['hub.challenge'];
  const token = d['hub.verify_token'];
  const expected = $env.META_WEBHOOK_VERIFY_TOKEN || '';
  const valid = mode === 'subscribe' && token === expected && !!challenge;
  return { json: { _token_valid: valid, _challenge: challenge, _token_error: valid ? null : 'Verify token mismatch' } };
});

const crypto = require('crypto');
const items = $input.all();
return items.map(item => {
  const headers = item.json.headers || item.json._headers || {};
  const signature = headers['x-hub-signature-256'] || '';
  const secret = $env.META_WEBHOOK_SECRET || '';
  if (!signature || !secret) return { json: { ...item.json, _sig_valid: false, _sig_error: 'Missing signature or secret' } };
  const raw = JSON.stringify(item.json.entry ? item.json : { body: item.json });
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(raw).digest('hex');
  return { json: { ...item.json, _sig_valid: signature === expected, _sig_error: signature === expected ? null : 'Signature mismatch' } };
});

const items = $input.all();
return items.map(item => {
  const value = item.json.entry?.[0]?.changes?.[0]?.value;
  if (!value) return { json: { ...item.json, _event_type: 'other' } };
  const statuses = value.statuses;
  if (statuses?.length) {
    const s = statuses[0];
    const errors = s.errors || [];
    return { json: { ...item.json, _event_type: s.status, _provider_message_id: s.id, _recipient_id: s.recipient_id, _status_timestamp: s.timestamp, _conversation_id: s.conversation?.id, _pricing: s.pricing, _errors: errors, _error_title: errors[0]?.title } };
  }
  const msgs = value.messages;
  if (msgs?.length) {
    const m = msgs[0];
    if (m.type === 'interactive' && m.interactive?.type === 'button_reply') {
      const parts = (m.interactive.button_reply.id || '').split('|');
      return { json: { ...item.json, _event_type: 'button_reply', _button_action: parts[0], order_id: parts.slice(1).join('|'), _provider_message_id: m.id, phone: m.from, _msg_timestamp: m.timestamp } };
    }
  }
  return { json: { ...item.json, _event_type: 'other' } };
});

const items = $input.all();
return items.map(item => {
  const action = item.json._button_action;
  const status = action === 'CONFIRM_ORDER' ? 'confirmed' : action === 'CANCEL_ORDER' ? 'cancelled' : 'unknown';
  return { json: { ...item.json, _new_status: status, _confirmation_time: new Date().toISOString() } };
});

