={{ (() => {
  const ev = $json._event_type;
  const upd = { status: ev };
  if (ev === 'delivered') upd.delivered_at = new Date().toISOString();
  if (ev === 'read') upd.read_at = new Date().toISOString();
  if (ev === 'failed') upd.error_message = $json._error_title || 'Webhook delivery failure';
  return upd;
})() }}
